keywords:
// Coverage for the additional security/data-critical rules
            // ensures the pack is selected even for commands whose
            // service name isn't in the general keyword list.
            "kms"

// Extra service keywords so newly-added rules reliably
            // select this pack even when `az` isn't the first keyword
            // in the command's token list.
            "keyvault"

// Extra service keywords so the pack is selected even when
            // the command doesn't start with a keyword in the common
            // list (e.g. `bq rm -r DATASET` doesn't start with "gcloud").
            "bq"

// Include method-call forms so `db.users.drop()` triggers the pack
            // even when run as a shell-quoted one-liner without `mongo`/`mongosh`.
            ".drop("

